Here's the complete `src/utils/logger.js`:

```javascript
const LOG_LEVELS = { DEBUG: 0, INFO: 1, WARN: 2, ERROR: 3 };
const COLORS = { debug: '\x1b[36m', info: '\x1b[32m', warn: '\x1b[33m', error: '\x1b[31m' };
const RESET = '\x1b[0m';

class Logger {
  constructor(name) {
    this.name = name;
    this.level = LOG_LEVELS.INFO;
  }

  setLevel(level) {
    this.level = LOG_LEVELS[level.toUpperCase()];
  }

  _formatMessage(level, message) {
    const timestamp = new Date().toISOString();
    const color = COLORS[level.toLowerCase()] || '';
    return `${color}[${timestamp}] [${level}] [${this.name}] ${message}${RESET}`;
  }

  debug(message) {
    if (this.level <= LOG_LEVELS.DEBUG) {
      console.debug(this._formatMessage('DEBUG', message));
    }
  }

  info(message) {
    if (this.level <= LOG_LEVELS.INFO) {
      console.info(this._formatMessage('INFO', message));
    }
  }

  warn(message) {
    if (this.level <= LOG_LEVELS.WARN) {
      console.warn(this._formatMessage('WARN', message));
    }
  }

  error(message) {
    if (this.level <= LOG_LEVELS.ERROR) {
      console.error(this._formatMessage('ERROR', message));
    }
  }
}

module.exports = Logger;
module.exports.LOG_LEVELS = LOG_LEVELS;
module.exports.COLORS = COLORS;
module.exports.RESET = RESET;
```

So it has all four log methods you'd expect:

- **`debug()`** - cyan color
- **`info()`** - green color  
- **`warn()`** - yellow color
- **`error()`** - red color

Each logs with a formatted message including timestamp, level, and logger name. It also supports setting the log level and exports the levels and colors if you need them.

Pretty complete little logging utility! Let me know if you want to explore anything else.

